#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeFlareNode: FfiConverter {

    typealias FfiType = UnsafeMutableRawPointer
    typealias SwiftType = FlareNode

    public static func lift(_ pointer: UnsafeMutableRawPointer) throws -> FlareNode {
        return FlareNode(unsafeFromRawPointer: pointer)
    }

    public static func lower(_ value: FlareNode) -> UnsafeMutableRawPointer {
        return value.uniffiClonePointer()
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> FlareNode {
        let v: UInt64 = try readInt(&buf)
        // The Rust code won't compile if a pointer won't fit in a UInt64.
        // We have to go via `UInt` because that's the thing that's the size of a pointer.
        let ptr = UnsafeMutableRawPointer(bitPattern: UInt(truncatingIfNeeded: v))
        if (ptr == nil) {
            throw UniffiInternalError.unexpectedNullPointer
        }
        return try lift(ptr!)
    }

    public static func write(_ value: FlareNode, into buf: inout [UInt8]) {
        // This fiddling is because `Int` is the thing that's the same size as a pointer.
        // The Rust code won't compile if a pointer won't fit in a `UInt64`.
        writeInt(&buf, UInt64(bitPattern: Int64(Int(bitPattern: lower(value)))))
    }
}




#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public func FfiConverterTypeFlareNode_lift(_ pointer: UnsafeMutableRawPointer) throws -> FlareNode {
    return try FfiConverterTypeFlareNode.lift(pointer)
}

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public func FfiConverterTypeFlareNode_lower(_ value: FlareNode) -> UnsafeMutableRawPointer {
    return FfiConverterTypeFlareNode.lower(value)
}


public struct FfiChatMessage {
    public var messageId: String
    public var conversationId: String
    public var senderDeviceId: String
    public var content: String
    public var timestampMs: Int64
    public var isOutgoing: Bool
    public var deliveryStatus: UInt8

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(messageId: String, conversationId: String, senderDeviceId: String, content: String, timestampMs: Int64, isOutgoing: Bool, deliveryStatus: UInt8) {
        self.messageId = messageId
        self.conversationId = conversationId
        self.senderDeviceId = senderDeviceId
        self.content = content
        self.timestampMs = timestampMs
        self.isOutgoing = isOutgoing
        self.deliveryStatus = deliveryStatus
    }
}



extension FfiChatMessage: Equatable, Hashable {
    public static func ==(lhs: FfiChatMessage, rhs: FfiChatMessage) -> Bool {
        if lhs.messageId != rhs.messageId {
            return false
        }
        if lhs.conversationId != rhs.conversationId {
            return false
        }
        if lhs.senderDeviceId != rhs.senderDeviceId {
            return false
        }
        if lhs.content != rhs.content {
            return false
        }
        if lhs.timestampMs != rhs.timestampMs {
            return false
        }
        if lhs.isOutgoing != rhs.isOutgoing {
            return false
        }
        if lhs.deliveryStatus != rhs.deliveryStatus {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(messageId)
        hasher.combine(conversationId)
        hasher.combine(senderDeviceId)
        hasher.combine(content)
        hasher.combine(timestampMs)
        hasher.combine(isOutgoing)
        hasher.combine(deliveryStatus)
    }
}


